def remove_peripheral_zeros(im):
    rows, cols = im.shape

    if im.size == 0 or np.all(np.abs(im) == 0):
        return np.empty((0, 0), dtype=im.dtype)

    # Identify rows and columns that are not entirely zero
    non_zero_rows = np.where(np.any(np.abs(im) > 0, axis=1))[0]
    non_zero_cols = np.where(np.any(np.any(np.abs(im) > 0, axis=0), axis=0))[0]

    # If there are no non-zero rows or columns, return empty
    if len(non_zero_rows) == 0 or len(non_zero_cols) == 0:
        return np.empty((0, 0), dtype=im.dtype)

    # Extract non-zero parts for remaining rows and columns
    # Start from the first non-zero index and end at the last non-zero index
    mask = np.zeros((rows, cols), dtype=bool)
    for i in range(rows):
        if i in non_zero_rows:
            start = i
            for j in range(i + 1, len(non_zero_rows)):
                if non_zero_rows[j] == i:
                    break
                start = non_zero_rows[j]
                continue
            for j in range(cols):
                if j in non_zero_cols:
                    break
                start = non_zero_cols[j]
                continue
            for j in range(start):
                mask[i, j] = True
    for i in range(rows):
        for j in range(cols):
            if i in non_zero_rows and j in non_zero_cols:
                mask[i, j] = True
            else:
                mask[i, j] = False

    return im[mask]
