import numpy as np

def to_binary_array_integers(input_array, m):
    if input_array is None or input_array.size == 0:
        return np.empty((0, m), dtype=int)

    if not np.issubdtype(input_array.dtype, np.integer):
        input_array = np.asarray(input_array, dtype=np.int_)

    input_array = np.asarray(input_array, dtype=np.uint8)
    result = np.zeros((input_array.shape[0], m), dtype=object)

    for i in range(input_array.shape[0]):
        binary = np.uint8_v2(input_array[i]).to_bytes()
        result[i] = binary

